"use client"

import { useState, useEffect, use } from "react"
import Image from "next/image"
import Link from "next/link"
import { useRouter } from "next/navigation"
import { 
  getIllustrationPosts, 
  deleteIllustrationPost, 
  addCommentToIllustration,
  hydrateStore,
  Post,
  Comment,
  generateId
} from "@/lib/store"
import { useAdmin } from "@/lib/admin-context"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Textarea } from "@/components/ui/textarea"
import { ArrowLeft, Trash2, ChevronLeft, ChevronRight, Send } from "lucide-react"

interface PageProps {
  params: Promise<{ postId: string }>
}

export default function IllustrationDetailPage({ params }: PageProps) {
  const { postId } = use(params)
  const router = useRouter()
  const { isAdmin } = useAdmin()
  const [post, setPost] = useState<Post | null>(null)
  const [currentImageIndex, setCurrentImageIndex] = useState(0)
  const [mounted, setMounted] = useState(false)
  const [loaded, setLoaded] = useState(false)
  const [commentAuthor, setCommentAuthor] = useState("")
  const [commentText, setCommentText] = useState("")

  const loadPost = () => {
    const posts = getIllustrationPosts()
    const found = posts.find(p => p.id === postId)
    setPost(found || null)
  }

  useEffect(() => {
    let active = true

    const loadPostWithHydration = async () => {
      setMounted(true)
      await hydrateStore()

      if (!active) return

      loadPost()
      setLoaded(true)
    }

    void loadPostWithHydration()

    return () => {
      active = false
    }
  }, [postId])

  const handleDelete = () => {
    if (!post) return
    if (confirm("정말 삭제하시겠습니까?")) {
      deleteIllustrationPost(post.id)
      router.push("/illustration")
    }
  }

  const handleCommentSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!post || !commentAuthor.trim() || !commentText.trim()) return

    const newComment: Comment = {
      id: generateId(),
      author: commentAuthor.trim(),
      text: commentText.trim(),
      createdAt: new Date().toISOString()
    }

    addCommentToIllustration(post.id, newComment)
    setCommentAuthor("")
    setCommentText("")
    loadPost()
  }

  const nextImage = () => {
    if (!post) return
    setCurrentImageIndex((prev) => (prev + 1) % post.images.length)
  }

  const prevImage = () => {
    if (!post) return
    setCurrentImageIndex((prev) => (prev - 1 + post.images.length) % post.images.length)
  }

  if (!mounted || !loaded) {
    return (
      <div className="flex flex-col items-center justify-center py-20">
        <p className="text-muted-foreground">작품을 불러오는 중입니다...</p>
      </div>
    )
  }

  if (!post) {
    return (
      <div className="flex flex-col items-center justify-center py-20">
        <p className="text-muted-foreground mb-4">작품을 찾을 수 없습니다</p>
        <Link href="/illustration">
          <Button variant="outline">
            <ArrowLeft className="w-4 h-4 mr-2" />
            목록으로 돌아가기
          </Button>
        </Link>
      </div>
    )
  }

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <Link href="/illustration">
          <Button variant="ghost" size="sm">
            <ArrowLeft className="w-4 h-4 mr-2" />
            목록으로
          </Button>
        </Link>
        {mounted && isAdmin && (
          <Button variant="destructive" size="sm" onClick={handleDelete}>
            <Trash2 className="w-4 h-4 mr-2" />
            삭제
          </Button>
        )}
      </div>

      {/* Image Gallery */}
      <div className="relative aspect-[4/3] rounded-lg overflow-hidden bg-muted">
        <Image
          src={post.images[currentImageIndex]}
          alt={`${post.title} - 이미지 ${currentImageIndex + 1}`}
          fill
          className="object-contain"
          priority
        />
        
        {post.images.length > 1 && (
          <>
            <button
              onClick={prevImage}
              className="absolute left-2 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-background/80 hover:bg-background flex items-center justify-center transition-colors"
            >
              <ChevronLeft className="w-6 h-6" />
            </button>
            <button
              onClick={nextImage}
              className="absolute right-2 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-background/80 hover:bg-background flex items-center justify-center transition-colors"
            >
              <ChevronRight className="w-6 h-6" />
            </button>
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex gap-2">
              {post.images.map((_, index) => (
                <button
                  key={index}
                  onClick={() => setCurrentImageIndex(index)}
                  className={`w-2 h-2 rounded-full transition-colors ${
                    index === currentImageIndex ? "bg-primary" : "bg-background/60"
                  }`}
                />
              ))}
            </div>
          </>
        )}
      </div>

      {/* Thumbnail strip */}
      {post.images.length > 1 && (
        <div className="flex gap-2 overflow-x-auto pb-2">
          {post.images.map((img, index) => (
            <button
              key={index}
              onClick={() => setCurrentImageIndex(index)}
              className={`relative w-20 h-20 rounded-md overflow-hidden flex-shrink-0 border-2 transition-colors ${
                index === currentImageIndex ? "border-primary" : "border-transparent"
              }`}
            >
              <Image
                src={img}
                alt={`썸네일 ${index + 1}`}
                fill
                className="object-cover"
              />
            </button>
          ))}
        </div>
      )}

      {/* Content */}
      <div className="space-y-4">
        <h1 className="text-2xl font-bold text-foreground">{post.title}</h1>
        <p className="text-sm text-muted-foreground">
          {new Date(post.createdAt).toLocaleDateString("ko-KR", {
            year: "numeric",
            month: "long",
            day: "numeric"
          })}
        </p>
        {post.description && (
          <p className="text-foreground whitespace-pre-wrap leading-relaxed">
            {post.description}
          </p>
        )}
      </div>

      {/* Comments Section */}
      <div className="border-t pt-6 space-y-6">
        <h2 className="text-lg font-semibold text-foreground">
          댓글 {post.comments?.length || 0}개
        </h2>

        {/* Comment Form */}
        <form onSubmit={handleCommentSubmit} className="space-y-3">
          <Input
            placeholder="닉네임"
            value={commentAuthor}
            onChange={(e) => setCommentAuthor(e.target.value)}
            className="max-w-xs"
          />
          <div className="flex gap-2">
            <Textarea
              placeholder="댓글을 작성하세요..."
              value={commentText}
              onChange={(e) => setCommentText(e.target.value)}
              rows={2}
              className="flex-1"
            />
            <Button 
              type="submit" 
              size="icon"
              disabled={!commentAuthor.trim() || !commentText.trim()}
            >
              <Send className="w-4 h-4" />
            </Button>
          </div>
        </form>

        {/* Comments List */}
        <div className="space-y-4">
          {post.comments && post.comments.length > 0 ? (
            post.comments.map((comment) => (
              <div key={comment.id} className="bg-muted/50 rounded-lg p-4">
                <div className="flex items-center gap-2 mb-2">
                  <span className="font-medium text-foreground">{comment.author}</span>
                  <span className="text-xs text-muted-foreground">
                    {new Date(comment.createdAt).toLocaleDateString("ko-KR")}
                  </span>
                </div>
                <p className="text-foreground text-sm">{comment.text}</p>
              </div>
            ))
          ) : (
            <p className="text-muted-foreground text-center py-4">
              아직 댓글이 없습니다. 첫 댓글을 남겨보세요!
            </p>
          )}
        </div>
      </div>
    </div>
  )
}
